$(function(){$(".delete-modal-button").on("click",function(){$(".delete-modal").modal("show")});$("#rate_modal_button").on("click",function(){$("#rate_modal").modal("show")});$(".radio-star").on("change",function(){$('form[name="rating"]').trigger("submit")});$(".dropdown-diet").on("click",function(e){e.stopPropagation()});$("#upload_file_button").on("click",function(event){$(this).next()[0].click();event.preventDefault()});$("#recipe_search_icon").on("click",function(event){$(this).next()[0].click();event.preventDefault()});$("#abc_select").on("change",function(){window.location.href=$("#abc_route").data("route")+"/"+$(this).val()});$('form[name="contact"]').on("submit",function(event){if($("#contact_re_captcha_token").val()===""){grecaptcha.ready(function(){grecaptcha.execute($("#re_captcha_key").data("key"),{action:"contact"}).then(function(token){$("#contact_re_captcha_token").val(token);$('[name="contact"]').trigger("submit")})});event.preventDefault()}});if($('input[name="recipe[isSelfInvented]"]:checked').val()==="0"){$("#recipe_source").removeClass("d-none")}$('input[name="recipe[isSelfInvented]"]').on("change",function(){if($(this).val()==="1"){$("#recipe_source_title").addClass("d-none");$("#recipe_source").addClass("d-none")}else{$("#recipe_source_title").removeClass("d-none");$("#recipe_source").removeClass("d-none")}});let recipesHomepage=$("#recipes_homepage");if(recipesHomepage.length>0&&!($("#recent_recipes_heading").length>0)){$("html, body").animate({scrollTop:recipesHomepage.offset().top},1e3)}$("#recipe_filter_icon").on("click",function(){let div=$("#filter_sort_div");if(div.hasClass("d-none")){div.removeClass("d-none")}else{div.addClass("d-none")}});$('form[name="rating"]').on("submit",function(event){let rating=$("#rating_rating");rating.text("");if(rating.val()<1||rating.val()>10){$("#form_errors_client").text("The waardering moet tussen 1 en 10 zijn.");event.preventDefault()}});let form=$(".food-form");if(form.length>0){new FoodForm(form)}});